r&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;display1&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;  &lt;span class=&#34;comment&#34;&gt;//打印通讯录&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	contact *p; &lt;span class=&#34;comment&#34;&gt;//定义结构体类型的指针&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	p = head;  &lt;span class=&#34;comment&#34;&gt;// 让p 等于当前head指针所指的节点&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;int&lt;/span&gt; i = &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;;  &lt;span class=&#34;comment&#34;&gt;//显示序号&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	cout&amp;lt;&amp;lt;endl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	cout&amp;lt;&amp;lt;&lt;span class=&#34;string&#34;&gt;&amp;quot;---------------------------------------- &amp;quot;&lt;/span&gt;&amp;lt;&amp;lt;endl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	cout&amp;lt;&amp;lt;&lt;span class=&#34;string&#34;&gt;&amp;quot;    通 讯 录     &amp;quot;&lt;/span&gt;&amp;lt;&amp;lt;endl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	cout&amp;lt;&amp;lt;&lt;span class=&#34;string&#34;&gt;&amp;quot;---------------------------------------- &amp;quot;&lt;/span&gt;&amp;lt;&amp;lt;endl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt;(p-&amp;gt;prev != &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;)            &lt;span class=&#34;comment&#34;&gt;//循环，知道p指向节点的prev指针指向NULL&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	cout&amp;lt;&amp;lt;&lt;span class=&#34;string&#34;&gt;&amp;quot; &amp;quot;&lt;/span&gt;&amp;lt;&amp;lt;i&amp;lt;&amp;lt;&lt;span class=&#34;string&#34;&gt;&amp;quot;:  &amp;quot;&lt;/span&gt;&amp;lt;&amp;lt;p-&amp;gt;NAME&amp;lt;&amp;lt;endl;       &lt;span class=&#34;comment&#34;&gt;//打印p指针对应节点的名字&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	cout&amp;lt;&amp;lt;&lt;span class=&#34;string&#34;&gt;&amp;quot;---------------------------------------- &amp;quot;&lt;/span&gt;&amp;lt;&amp;lt;endl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	p = p-&amp;gt;prev;             &lt;span class=&#34;comment&#34;&gt;//指针指向上一个节点&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	i++;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	cout&amp;lt;&amp;lt;&lt;span class=&#34;string&#34;&gt;&amp;quot;---------------------------------------- &amp;quot;&lt;/span&gt;&amp;lt;&amp;lt;endl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	cout&amp;lt;&amp;lt;endl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;save&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	contact *p;         &lt;span class=&#34;comment&#34;&gt;//定义结构体类型的指针&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	p = &amp;amp;dn;          &lt;span class=&#34;comment&#34;&gt;// 让p 等于当前head指针所指的节点&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;int&lt;/span&gt; i = &lt;span class=&#34;number&#34;&gt;1&lt;/span&gt;;          &lt;span class=&#34;comment&#34;&gt;//通讯录的序号&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;function&#34;&gt;ofstream &lt;span class=&#34;title&#34;&gt;fout&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(&lt;span class=&#34;string&#34;&gt;&amp;quot;tongxunlu.txt&amp;quot;&lt;/span&gt;)&lt;/span&gt;&lt;/span&gt;;     &lt;span class=&#34;comment&#34;&gt;//打开这个文件，并且把通讯录内容导入进去&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;while&lt;/span&gt;(p-&amp;gt;prev!= &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;)       &lt;span class=&#34;comment&#34;&gt;//循环，知道p指向节点的prev指针指向空,&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	fout &amp;lt;&amp;lt; p-&amp;gt;NAME&amp;lt;&amp;lt;endl;   &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	fout &amp;lt;&amp;lt; p-&amp;gt;EIP&amp;lt;&amp;lt;endl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	fout &amp;lt;&amp;lt; p-&amp;gt;STREET&amp;lt;&amp;lt;endl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	fout &amp;lt;&amp;lt; p-&amp;gt;CITY&amp;lt;&amp;lt;endl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	fout &amp;lt;&amp;lt; p-&amp;gt;STATE&amp;lt;&amp;lt;endl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	p = p-&amp;gt;prev;        &lt;span class=&#34;comment&#34;&gt;//指针指向上一个节点&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	i++;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	fout.&lt;span class=&#34;built_in&#34;&gt;close&lt;/span&gt;();         &lt;span class=&#34;comment&#34;&gt;//关闭文件&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;span class=&#34;keyword&#34;&gt;void&lt;/span&gt; &lt;span class=&#34;title&#34;&gt;display&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;(contact *P)&lt;/span&gt;&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;if&lt;/span&gt;(P == &lt;span class=&#34;literal&#34;&gt;NULL&lt;/span&gt;) &lt;span class=&#34;comment&#34;&gt;// 判断 如果P为空，那么没有这个人&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	cout&amp;lt;&amp;lt;&lt;span class=&#34;string&#34;&gt;&amp;quot;通讯录中不存在这个人&amp;quot;&lt;/span&gt;&amp;lt;&amp;lt;endl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#125;&lt;span class=&#34;keyword&#34;&gt;else&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	cout&amp;lt;&amp;lt;&lt;span class=&#34;string&#34;&gt;&amp;quot;---------------------------------------- &amp;quot;&lt;/span&gt;&amp;lt;&amp;lt;endl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	cout&amp;lt;&amp;lt;&lt;span class=&#34;string&#34;&gt;&amp;quot;* 姓名: &amp;quot;&lt;/span&gt;&amp;lt;&amp;lt;P-&amp;gt;NAME&amp;lt;&amp;lt;endl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	cout&amp;lt;&amp;lt;&lt;span class=&#34;string&#34;&gt;&amp;quot;* 邮编: &amp;quot;&lt;/span&gt;&amp;lt;&amp;lt;P-&amp;gt;EIP&amp;lt;&amp;lt;endl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	cout&amp;lt;&amp;lt;&lt;span class=&#34;string&#34;&gt;&amp;quot;* 街道: &amp;quot;&lt;/span&gt;&amp;lt;&amp;lt;P-&amp;gt;STREET&amp;lt;&amp;lt;endl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	cout&amp;lt;&amp;lt;&lt;span class=&#34;string&#34;&gt;&amp;quot;* 城市: &amp;quot;&lt;/span&gt;&amp;lt;&amp;lt;P-&amp;gt;CITY&amp;lt;&amp;lt;endl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	cout&amp;lt;&amp;lt;&lt;span class=&#34;string&#34;&gt;&amp;quot;* 国家:&amp;quot;&lt;/span&gt;&amp;lt;&amp;lt;P-&amp;gt;STATE&amp;lt;&amp;lt;endl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	cout&amp;lt;&amp;lt;&lt;span class=&#34;string&#34;&gt;&amp;quot;---------------------------------------- &amp;quot;&lt;/span&gt;&amp;lt;&amp;lt;endl;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;function&#34;&gt;contact* &lt;span class=&#34;title&#34;&gt;load&lt;/span&gt;&lt;span class=&#34;params&#34;&gt;()&lt;/span&gt;&lt;/span&gt;&amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;	&lt;span class=&#34;keyword&#34;&gt;return&lt;/span&gt; head;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
